    88→
    89→/* ─────────────────────────────────────────────────────────────────────────────
    90→   BRAND PALETTE OFICIAL (5 colores)
    91→   #031E43  Prussian Blue  → primary / foreground text
    92→   #3B506D  Dusk Blue      → texto muted / secundario
    93→   #FDFDFB  Off-White      → fondo light / texto claro dark
    94→   #FFFFFF  Pure White     → cards y superficies blancas
    95→   #DDDFE2  Alabaster Grey → bordes, divisores, fondos sutiles
    96→
    97→   HSL conversiones:
    98→   #031E43 → hsl(215 91% 14%)
    99→   #3B506D → hsl(215 30% 33%)
   100→   #FDFDFB → hsl(60 1% 99%)
   101→   #FFFFFF → hsl(0 0% 100%)
   102→   #DDDFE2 → hsl(216 4% 88%)
   103→   ───────────────────────────────────────────────────────────────────────────── */
   104→
   105→/* LIGHT MODE */
   106→:root {
   107→  /* Navy → paleta brand light */
   108→  --theme-white:      #031E43;   /* text-white = Prussian Blue en light */
   109→  --theme-navy:       #FDFDFB;   /* Off-White */
   110→  --theme-navy-2:     #DDDFE2;   /* Alabaster Grey */
   111→  --theme-navy-3:     #EDEEF0;   /* entre Off-White y Alabaster */
   112→  --theme-navy-card:  #FFFFFF;   /* Cards Pure White sobre fondo Off-White */
   113→  --theme-navy-card2: #FAFAFA;
   114→
   115→  --button-outline: rgba(3,30,67, .12);
   116→  --badge-outline:  rgba(3,30,67, .06);
   117→
   118→  --opaque-button-border-intensity: -8;
   119→
   120→  --elevate-1: rgba(3,30,67, .03);
   121→  --elevate-2: rgba(3,30,67, .07);
   122→
   123→  /* surfaces */
   124→  --background: 60 1% 99%;         /* Off-White #FDFDFB */
   125→  --foreground: 215 91% 14%;       /* Prussian Blue #031E43 */
   126→  --border: 216 4% 88%;            /* Alabaster Grey #DDDFE2 */
   127→  --input: 216 4% 88%;             /* Alabaster Grey */
   128→  --ring: 215 91% 14%;             /* Prussian Blue */
   129→
   130→  /* cards */
   131→  --card: 0 0% 100%;               /* Pure White */
   132→  --card-foreground: 215 91% 14%;
   133→  --card-border: 216 4% 88%;       /* Alabaster Grey */
   134→
   135→  /* popovers */
   136→  --popover: 0 0% 100%;
   137→  --popover-foreground: 215 91% 14%;
   138→  --popover-border: 216 4% 88%;
   139→
   140→  /* primary = Prussian Blue */
   141→  --primary: 215 91% 14%;
   142→  --primary-foreground: 60 1% 99%; /* Off-White */
   143→
   144→  /* secondary = Alabaster Grey */
   145→  --secondary: 216 4% 88%;         /* #DDDFE2 */
   146→  --secondary-foreground: 215 91% 14%;
   147→
   148→  /* muted */
   149→  --muted: 216 4% 88%;             /* Alabaster Grey */
   150→  --muted-foreground: 215 30% 33%; /* Dusk Blue #3B506D */
   151→
   152→  /* accent = Gold (se mantiene) */
   153→  --accent: 43 63% 47%;
   154→  --accent-foreground: 215 91% 14%;
   155→
   156→  --destructive: 0 84% 60%;
   157→  --destructive-foreground: 0 0% 100%;
   158→
   159→  --radius: 0.75rem;
   160→
   161→  /* sidebar */
   162→  --sidebar: 0 0% 100%;
   163→  --sidebar-foreground: 215 91% 14%;
   164→  --sidebar-border: 216 4% 88%;
   165→  --sidebar-primary: 215 91% 14%;
   166→  --sidebar-primary-foreground: 0 0% 100%;
   167→  --sidebar-accent: 216 4% 88%;
   168→  --sidebar-accent-foreground: 215 91% 14%;
   169→  --sidebar-ring: 215 91% 14%;
   170→
   171→  /* charts — derivados del brand */
   172→  --chart-1: 43 63% 47%;           /* Gold */
   173→  --chart-2: 215 91% 14%;          /* Prussian Blue */
   174→  --chart-3: 215 30% 33%;          /* Dusk Blue */
   175→  --chart-4: 216 4% 88%;           /* Alabaster Grey */
   176→  --chart-5: 215 60% 26%;          /* Prussian Blue intermedio */
   177→}
   178→
   179→/* DARK MODE */
   180→.dark {
   181→  /* Navy → tonos oscuros derivados de Prussian Blue */
   182→  --theme-white:      #FDFDFB;   /* text-white = Off-White en dark */
   183→  --theme-navy:       #020f21;   /* más oscuro que Prussian */
   184→  --theme-navy-2:     #021630;
   185→  --theme-navy-3:     #031E43;   /* Prussian Blue como nivel medio */
   186→  --theme-navy-card:  #031E43;   /* Prussian Blue para cards */
   187→  --theme-navy-card2: #021630;
   188→
   189→  --button-outline: rgba(221,223,226, .15);
   190→  --badge-outline:  rgba(221,223,226, .08);
   191→
   192→  --opaque-button-border-intensity: 9;
   193→
   194→  --elevate-1: rgba(221,223,226, .04);
   195→  --elevate-2: rgba(221,223,226, .09);
   196→
   197→  /* surfaces */
   198→  --background: 215 91% 10%;       /* más oscuro que Prussian */
   199→  --foreground: 60 1% 99%;         /* Off-White #FDFDFB */
   200→  --border: 216 4% 88%;            /* Alabaster Grey — opacity en uso */
   201→  --input: 215 91% 14%;            /* Prussian Blue */
   202→  --ring: 43 63% 47%;              /* Gold */
   203→
   204→  /* cards = Prussian Blue */
   205→  --card: 215 91% 14%;             /* #031E43 Prussian Blue */
   206→  --card-foreground: 60 1% 99%;
   207→  --card-border: 216 4% 88%;       /* Alabaster Grey */
   208→
   209→  /* popovers */
   210→  --popover: 215 91% 14%;
   211→  --popover-foreground: 60 1% 99%;
   212→  --popover-border: 216 4% 88%;
   213→
   214→  /* primary = Gold (accent principal en dark) */
   215→  --primary: 43 63% 47%;
   216→  --primary-foreground: 215 91% 10%;
   217→
   218→  /* secondary = Prussian ligeramente más claro */
   219→  --secondary: 215 60% 22%;
   220→  --secondary-foreground: 60 1% 99%;
   221→
   222→  /* muted */
   223→  --muted: 215 70% 18%;
   224→  --muted-foreground: 215 30% 33%; /* Dusk Blue #3B506D */
   225→
   226→  /* accent = Gold */
   227→  --accent: 43 63% 47%;
   228→  --accent-foreground: 215 91% 10%;
   229→
   230→  --destructive: 0 62.8% 30.6%;
   231→  --destructive-foreground: 0 0% 100%;
   232→
   233→  /* sidebar */
   234→  --sidebar: 215 91% 10%;
   235→  --sidebar-foreground: 60 1% 99%;
   236→  --sidebar-border: 216 4% 88%;
   237→  --sidebar-primary: 43 63% 47%;
   238→  --sidebar-primary-foreground: 215 91% 10%;
   239→  --sidebar-accent: 215 91% 14%;
   240→  --sidebar-accent-foreground: 60 1% 99%;
   241→  --sidebar-ring: 43 63% 47%;
   242→
   243→  /* charts */
   244→  --chart-1: 43 63% 47%;           /* Gold */
   245→  --chart-2: 215 91% 14%;          /* Prussian Blue */
   246→  --chart-3: 215 30% 33%;          /* Dusk Blue */
   247→  --chart-4: 216 4% 88%;           /* Alabaster Grey */
   248→  --chart-5: 215 60% 26%;          /* Prussian Blue intermedio */
   249→}
