   264→/* ──────────────────────────────────────────────────────────────────── */
   265→.hero-bg { background: #FDFDFB; position: relative; overflow: hidden; }
   266→.hero-bg::before { content: ''; position: absolute; width: 700px; height: 700px; background: radial-gradient(circle, rgba(3,30,67,.04) 0%, transparent 70%); top: -150px; right: -150px; pointer-events: none; }
   267→.gradient-badge { background: linear-gradient(135deg, #031E43, #3B506D); }
   268→.dark-section { background: #031E43; }
   269→.light-section { background: #FDFDFB; }
   270→.card-hover { transition: transform .25s, box-shadow .25s; }
